<template>
    <div>
        <div style="margin-bottom: 20px">
            <el-input style="width: 240px" placeholder="请输入图书名称" v-model="params.name"></el-input>
            <el-button style="margin-left: 5px" type="primary" round @click="load"><i class="el-icon-search" ></i>搜索</el-button>
            <el-button style="margin-left: 5px" type="info" round @click="reset"><i class="el-icon-refresh-right" ></i>重置</el-button>
            <el-button style="margin-left: 5px" type="warning" round @click="change"><i class="el-icon-star-off" ></i>添加</el-button>

        </div>
        <el-table :data="tableData" stripe row-key="id" default-expand-all :border="true" size="medium">
            <el-table-column prop="name" label="图书名称" ></el-table-column>
<!--            <el-table-column prop="description" label="描述" ></el-table-column>-->
<!--            <el-table-column prop="author" label="作者"></el-table-column>-->
            <el-table-column prop="category" label="类别"></el-table-column>
<!--            <el-table-column prop="bookNo" label="标准码"></el-table-column>-->
            <el-table-column prop="publish" label="出版社"></el-table-column>
            <el-table-column prop="number" label="数量" ></el-table-column>
<!--            <el-table-column prop="cover" label="封面" >-->
<!--                <template v-slot="scope">-->
<!--                    <el-image :src="scope.row.cover" :preview-src-list="[scope.row.cover]"></el-image>-->
<!--                </template>-->
<!--            </el-table-column>-->
            <el-table-column label="其它信息">
                <template v-slot="scope">
                    <el-button style="background-color: #f9a7a7" icon="el-icon-zoom-in" @click="$router.push('/detailBook?id=' + scope.row.id)">查看</el-button>
                </template>
            </el-table-column>
<!--            <el-table-column prop="createtime" label="创建时间"></el-table-column>-->
<!--            <el-table-column prop="updatetime" label="更新时间"></el-table-column>-->
<!--            <el-table-column></el-table-column>-->
            <el-table-column label="操作" >
                <template v-slot="scope">
                    <!--                scope.row就是当前行数据-->
<!--                    <el-button type="success" v-if="!scope.row.pid" @click="handleAdd(scope.row)">添加二级分类</el-button>-->
                    <el-button style="background-color: darkcyan; color: white" icon="el-icon-edit" @click="$router.push('/editBook?id=' + scope.row.id)">编辑</el-button>
                    <el-popconfirm
                            style="margin-left: 5px"
                            title="您确定删除吗？"
                            @confirm="del(scope.row.id)"
                    >
                        <el-button type="danger" icon="el-icon-delete" slot="reference">删除</el-button>
                    </el-popconfirm>
<!--                    <el-button type="primary" @click="" style="margin-left: 5px" @click="$router.push('/detailAdmin?id=' + scope.row.id)">详情</el-button>-->
<!--                    @click执行跳转页面和将数据带过去的操作，得到了id,需要后台UserController.java提供根据id查询的接口-->
                </template>
            </el-table-column>
        </el-table>

        <!--      分页-->
        <div style="margin-top: 20px">
            <el-pagination
                    background
                    :current-page="params.pageNum"
                    :page-size="params.pageSize"
                    layout="prev, pager, next"
                    @current-change="handleCurrentChange"
                    :total="total">
                <!--              tableData.length为当前表格的总个数-->
            </el-pagination>
        </div>

    </div>
</template>

<script>
    import request from "@/utils/request";
    import Cookies from 'js-cookie';
    export default {
        name: 'BookList',
        data(){
            return{
                admin: Cookies.get('admin') ? JSON.parse(Cookies.get('admin')) : {},
                tableData:[

                ],
                total: 0,
                params: {
                    pageNum: 1,
                    pageSize: 10,
                    name: '',
                    bookNo: '',
                },
                rules:{
                    name: [
                        {required: true, message: '请输入分类名称', trigger: 'blur'},
                        {min: 3, max: 10, message: '长度在 3 到 10 个字符', trigger: 'blur'}
                    ],
                }
            }
        },
        created() {
            this.load()

        },
        methods: {
            
            load() {
                request.get('/book/page',{params: this.params}).then(res =>{
                    if(res.code === '200'){
                        this.tableData = res.data.list
                        this.total = res.data.total

                    }

                })
            },
            reset(){
                this.params = {
                    pageNum: 1,
                    pageSize: 10,
                    name: '',
                    bookNo:'',


                }
                this.load()
            },
            add(){
                this.params = {
                    pageNum: 1,
                    pageSize: 10,
                    name: '',
                    bookNo:'',


                }
                this.load()

            },

            handleCurrentChange(pageNum){
                //点击分页按钮触发分页
                this.params.pageNum = pageNum;
                this.load();
            },
            del(id){
                request.delete("/book/delete/"+id).then(res =>{
                    if(res.code === '200'){
                        this.$notify.success('删除成功');
                        this.load();
                    //    this.load()用来从新加载数据
                    }else{
                        this.$notify.error(res.msg)
                    }
                })
            },
            change(){
                this.$router.push('addBook')
            }

        }


    }
</script>
